@function modular-scale(
  $increment,
  $value: _fetch-bourbon-setting("modular-scale-base"),
  $ratio: _fetch-bourbon-setting("modular-scale-ratio")
) {
  $v1: nth($value, 1);
  $v2: nth($value, length($value));
  $value: $v1;

  // scale $v2 to just above $v1
  @while $v2 > $v1 {
    $v2: ($v2 / $ratio); // will be off-by-1
  }
  @while $v2 < $v1 {
    $v2: ($v2 * $ratio); // will fix off-by-1
  }

  // check AFTER scaling $v2 to prevent double-counting corner-case
  $double-stranded: $v2 > $v1;

  @if $increment > 0 {
    @for $i from 1 through $increment {
      @if $double-stranded and ($v1 * $ratio) > $v2 {
        $value: $v2;
        $v2: ($v2 * $ratio);
      } @else {
        $v1: ($v1 * $ratio);
        $value: $v1;
      }
    }
  }

  @if $increment < 0 {
    // adjust $v2 to just below $v1
    @if $double-stranded {
      $v2: ($v2 / $ratio);
    }

    @for $i from $increment through -1 {
      @if $double-stranded and ($v1 / $ratio) < $v2 {
        $value: $v2;
        $v2: ($v2 / $ratio);
      } @else {
        $v1: ($v1 / $ratio);
        $value: $v1;
      }
    }
  }

  @return $value;
}

// stylelint-disable-next-line selector-max-id
#carbonads {
  max-width: 28rem;
  padding: .75rem;
  margin-right: auto;
  margin-left: auto;
  overflow: auto;
  background-color: var(--bs-tertiary-bg);
  border-radius: .25rem;

  @media (min-width: 992px) {
    margin-right: 0;
    margin-left: 0;
  }
}

.carbon-img {
  float: left;
  margin-right: .75rem;

  @media (min-width: 768px) {
    margin-bottom: .5rem;
  }

  @media (min-width: 992px) {
    margin-bottom: 0;
  }
}

.carbon-text,
.carbon-poweredby {
  display: block;
  color: var(--bs-body-color);

  &:hover,
  &:focus {
    color: var(--bs-body-color);
    text-decoration: none;
  }
}

.carbon-text {
  margin-bottom: .5rem;
  text-decoration: none;

  @media (min-width: 768px) {
    font-size: .875rem;
  }
}

.carbon-poweredby {
  margin-top: .75rem;
  font-size: .875rem;
}

// Circle badge icon with drop shadow for icons and logos

.CircleBadge {
  display: flex;
  align-items: center;
  justify-content: center;
  background-color: var(--bgColor-default, var(--color-canvas-default));
  border-radius: 50%;
  box-shadow: var(--shadow-resting-medium, var(--color-shadow-medium));
}

.CircleBadge-icon {
  max-width: 60% !important;
  height: auto !important;
  max-height: 55% !important;
}

// Small badge
.CircleBadge--small {
  width: 56px;
  height: 56px;
}

// Medium badge
.CircleBadge--medium {
  width: 96px;
  height: 96px;
}

// Large badge
.CircleBadge--large {
  width: 128px;
  height: 128px;
}

// Dashed line that connects badges..
// Wrap around 2 or more badges to create a horizonal line:

.DashedConnection {
  position: relative;

  &::before {
    position: absolute;
    top: 50%;
    left: 0;
    width: 100%;
    content: '';
    // stylelint-disable-next-line primer/borders
    border-bottom: 2px dashed var(--borderColor-default, var(--color-border-default));
  }

  .CircleBadge {
    position: relative;
  }
}

//
// Pager pagination
// --------------------------------------------------


.pager {
  padding-left: 0;
  margin: $line-height-computed 0;
  text-align: center;
  list-style: none;
  @include clearfix;
  li {
    display: inline;
    > a,
    > span {
      display: inline-block;
      padding: 5px 14px;
      background-color: $pager-bg;
      border: 1px solid $pager-border;
      border-radius: $pager-border-radius;
    }

    > a:hover,
    > a:focus {
      text-decoration: none;
      background-color: $pager-hover-bg;
    }
  }

  .next {
    > a,
    > span {
      float: right;
    }
  }

  .previous {
    > a,
    > span {
      float: left;
    }
  }

  .disabled {
    > a,
    > a:hover,
    > a:focus,
    > span {
      color: $pager-disabled-color;
      cursor: $cursor-disabled;
      background-color: $pager-bg;
    }
  }
}

// Meters
// Credit: https://css-tricks.com/html5-meter-element/
.meter {
  appearance: none;
  background: $bg-color;
  border: 0;
  border-radius: $border-radius;
  display: block;
  width: 100%;
  height: $unit-4;

  &::-webkit-meter-inner-element {
    display: block;
  }

  &::-webkit-meter-bar,
  &::-webkit-meter-optimum-value,
  &::-webkit-meter-suboptimum-value,
  &::-webkit-meter-even-less-good-value {
    border-radius: $border-radius;
  }

  &::-webkit-meter-bar {
    background: $bg-color;
  }

  &::-webkit-meter-optimum-value {
    background: $success-color;
  }

  &::-webkit-meter-suboptimum-value {
    background: $warning-color;
  }

  &::-webkit-meter-even-less-good-value {
    background: $error-color;
  }

  &::-moz-meter-bar,
  &:-moz-meter-optimum,
  &:-moz-meter-sub-optimum,
  &:-moz-meter-sub-sub-optimum {
    border-radius: $border-radius;
  }

  &:-moz-meter-optimum::-moz-meter-bar {
    background: $success-color;
  }

  &:-moz-meter-sub-optimum::-moz-meter-bar {
    background: $warning-color;
  }

  &:-moz-meter-sub-sub-optimum::-moz-meter-bar {
    background: $error-color;
  }
}

// Timelines
.timeline {
  .timeline-item {
    display: flex;
    margin-bottom: $unit-6;
    position: relative;
    &::before {
      background: $border-color;
      content: "";
      height: 100%;
      left: 11px;
      position: absolute;
      top: $unit-6;
      width: 2px;
    }

    .timeline-left {
      flex: 0 0 auto;
    }

    .timeline-content {
      flex: 1 1 auto;
      padding: 2px 0 2px $layout-spacing-lg;
    }

    .timeline-icon {
      align-items: center;
      border-radius: 50%;
      color: $light-color;
      display: flex;
      height: $unit-6;
      justify-content: center;
      text-align: center;
      width: $unit-6;
      &::before {
        border: $border-width-lg solid $primary-color;
        border-radius: 50%;
        content: "";
        display: block;
        height: $unit-2;
        left: $unit-2;
        position: absolute;
        top: $unit-2;
        width: $unit-2;
      }

      &.icon-lg {
        background: $primary-color;
        line-height: $line-height;
        &::before {
          content: none;
        }
      }
    }
  }
}

// Button variant mixin
@mixin button-variant($color: $primary-color) {
  background: $color;
  border-color: darken($color, 3%);
  color: $light-color;
  &:focus {
    @include control-shadow($color);
  }
  &:focus,
  &:hover {
    background: darken($color, 2%);
    border-color: darken($color, 5%);
    color: $light-color;
  }
  &:active,
  &.active {
    background: darken($color, 7%);
    border-color: darken($color, 10%);
    color: $light-color;
  }
  &.loading {
    &::after {
      border-bottom-color: $light-color;
      border-left-color: $light-color;
    }
  }
}

@mixin button-outline-variant($color: $primary-color) {
  background: $light-color;
  border-color: $color;
  color: $color;
  &:focus {
    @include control-shadow($color);
  }
  &:focus,
  &:hover {
    background: lighten($color, 50%);
    border-color: darken($color, 2%);
    color: $color;
  }
  &:active,
  &.active {
    background: $color;
    border-color: darken($color, 5%);
    color: $light-color;
  }
  &.loading {
    &::after {
      border-bottom-color: $color;
      border-left-color: $color;
    }
  }
}

// Divider
.divider,
.divider-vert {
  display: block;
  position: relative;

  &[data-content]::after {
    background: $bg-color-light;
    color: $gray-color;
    content: attr(data-content);
    display: inline-block;
    font-size: $font-size-sm;
    padding: 0 $unit-2;
    transform: translateY(-$font-size-sm + $border-width);
  }
}

.divider {
  border-top: $border-width solid $border-color-light;
  height: $border-width;
  margin: $unit-2 0;

  &[data-content] {
    margin: $unit-4 0;
  }
}

.divider-vert {
  display: block;
  padding: $unit-4;

  &::before {
    border-left: $border-width solid $border-color;
    bottom: $unit-2;
    content: "";
    display: block;
    left: 50%;
    position: absolute;
    top: $unit-2;
    transform: translateX(-50%);
  }

  &[data-content]::after {
    left: 50%;
    padding: $unit-1 0;
    position: absolute;
    top: 50%;
    transform: translate(-50%, -50%);
  }
}

// Base class
//
// Requires one of the contextual, color modifier classes for `color` and
// `background-color`.

.badge {
  // scss-docs-start badge-css-vars
  --#{$prefix}badge-padding-x: #{$badge-padding-x};
  --#{$prefix}badge-padding-y: #{$badge-padding-y};
  @include rfs($badge-font-size, --#{$prefix}badge-font-size);
  --#{$prefix}badge-font-weight: #{$badge-font-weight};
  --#{$prefix}badge-color: #{$badge-color};
  --#{$prefix}badge-border-radius: #{$badge-border-radius};
  // scss-docs-end badge-css-vars

  display: inline-block;
  padding: var(--#{$prefix}badge-padding-y) var(--#{$prefix}badge-padding-x);
  @include font-size(var(--#{$prefix}badge-font-size));
  font-weight: var(--#{$prefix}badge-font-weight);
  line-height: 1;
  color: var(--#{$prefix}badge-color);
  text-align: center;
  white-space: nowrap;
  vertical-align: baseline;
  @include border-radius(var(--#{$prefix}badge-border-radius));
  @include gradient-bg();

  // Empty badges collapse automatically
  &:empty {
    display: none;
  }
}

// Quick fix for badges in buttons
.btn .badge {
  position: relative;
  top: -1px;
}

@use '../m2/theming' as m2-theming;
@use '../m2/palette' as m2-palette;

// @deprecated Use `get-color-from-palette`.
@function color($palette, $hue: default, $opacity: null) {
  @return m2-theming.get-color-from-palette($palette, $hue, $opacity);
}

// @deprecated Use `get-contrast-color-from-palette`.
@function contrast($palette, $hue) {
  @return m2-theming.get-contrast-color-from-palette($palette, $hue);
}

// @deprecated Use `define-palette`.
@function palette($base-palette, $default: 500, $lighter: 100, $darker: 700, $text: $default) {
  @return m2-theming.define-palette($base-palette, $default, $lighter, $darker, $text);
}

// @deprecated Use `define-light-theme`.
@function dark-theme($primary, $accent: null, $warn: palette(m2-palette.$red-palette)) {
  @return m2-theming.define-dark-theme($primary, $accent, $warn);
}

// @deprecated Use `define-light-theme`.
@function light-theme($primary, $accent: null, $warn: palette(m2-palette.$red-palette)) {
  @return m2-theming.define-light-theme($primary, $accent, $warn);
}

@import "./accordion-group";
@import "../accordion/accordion.md.vars";

// Material Design Accordion Group
// --------------------------------------------------

:host(.accordion-group-expand-inset) ::slotted(ion-accordion) {
  box-shadow: $accordion-md-box-shadow;
}

:host(.accordion-group-expand-inset) ::slotted(ion-accordion.accordion-expanding),
:host(.accordion-group-expand-inset) ::slotted(ion-accordion.accordion-expanded) {
  @include margin($accordion-md-expanded-margin, 0, $accordion-md-expanded-margin, 0);
  @include border-radius($accordion-md-border-radius, $accordion-md-border-radius, $accordion-md-border-radius, $accordion-md-border-radius);
}

:host(.accordion-group-expand-inset) ::slotted(ion-accordion.accordion-previous) {
  @include border-radius(null, null, $accordion-md-border-radius, $accordion-md-border-radius);
}

:host(.accordion-group-expand-inset) ::slotted(ion-accordion.accordion-next) {
  @include border-radius($accordion-md-border-radius, $accordion-md-border-radius, null, null);
}

:host(.accordion-group-expand-inset) ::slotted(ion-accordion):first-of-type {
  @include margin(0, 0, 0, 0);
}

@import "../../themes/ionic.globals";

// Datetime Button
// --------------------------------------------------

:host {
  display: flex;

  flex-wrap: wrap;

  align-items: center;

  justify-content: center;
}

:host button {
  @include border-radius(8px);
  @include margin(0px, 2px, 0px, 2px);

  position: relative;

  transition: 150ms color ease-in-out;

  border: none;

  background: var(--ion-color-step-300, var(--ion-background-color-step-300, #edeef0));

  color: $text-color;

  font-family: inherit;
  font-size: dynamic-font(16px);

  cursor: pointer;

  overflow: hidden;

  appearance: none;
}

:host(.time-active) #time-button,
:host(.date-active) #date-button {
  color: current-color(base);
}

:host(.datetime-button-disabled) {
  pointer-events: none;
}

:host(.datetime-button-disabled) button {
  opacity: 0.4;
}

@import "./loading";
@import "./loading.ios.vars";

// iOS Loading Indicator
// --------------------------------------------------

:host {
  --background: #{$loading-ios-background-color};
  --max-width: #{$loading-ios-max-width};
  --max-height: #{$loading-ios-max-height};
  --spinner-color: #{$loading-ios-spinner-color};
  --backdrop-opacity: var(--ion-backdrop-opacity, 0.3);

  color: $loading-ios-text-color;

  font-size: $loading-ios-font-size;
}

.loading-wrapper {
  @include border-radius($loading-ios-border-radius);
  @include padding($loading-ios-padding-top, $loading-ios-padding-end, $loading-ios-padding-bottom, $loading-ios-padding-start);
}


// iOS Translucent Loading
// -----------------------------------------

@supports (backdrop-filter: blur(0)) {
  :host(.loading-translucent) .loading-wrapper {
    background-color: $loading-ios-translucent-background-color;
    backdrop-filter: $loading-ios-translucent-filter;
  }
}


// iOS Loading Content
// -----------------------------------------

.loading-content {
  font-weight: $loading-ios-content-font-weight;
}

.loading-spinner + .loading-content {
  @include margin-horizontal(16px, null);
}

@import "./loading";
@import "./loading.md.vars";

// Material Design Loading Indicator
// --------------------------------------------------

:host {
  --background: #{$loading-md-background};
  --max-width: #{$loading-md-max-width};
  --max-height: #{$loading-md-max-height};
  --spinner-color: #{$loading-md-spinner-color};
  --backdrop-opacity: var(--ion-backdrop-opacity, 0.32);

  color: $loading-md-text-color;

  font-size: $loading-md-font-size;
}

.loading-wrapper {
  @include border-radius($loading-md-border-radius);
  @include padding($loading-md-padding-top, $loading-md-padding-end, $loading-md-padding-bottom, $loading-md-padding-start);

  box-shadow: $loading-md-box-shadow;
}


// Material Design Loading Content
// -----------------------------------------

.loading-spinner + .loading-content {
  @include margin-horizontal(16px, null);
}

@import "./picker-column";
@import "../picker-legacy/picker.ios.vars";

// iOS Picker Column
// --------------------------------------------------

.picker-col {
  @include padding($picker-ios-column-padding-top, $picker-ios-column-padding-end, $picker-ios-column-padding-bottom, $picker-ios-column-padding-start);

  transform-style: preserve-3d;
}

.picker-prefix,
.picker-suffix,
.picker-opts {
  top: $picker-ios-option-offset-y;

  transform-style: preserve-3d;

  color: inherit;

  font-size: $picker-ios-option-font-size;

  line-height: $picker-ios-option-height;
  pointer-events: none;
}

.picker-opt {
  @include padding($picker-ios-option-padding-top, $picker-ios-option-padding-end, $picker-ios-option-padding-bottom, $picker-ios-option-padding-start);
  @include margin(0);
  @include transform-origin(center, center);

  height: 46px;

  transform-style: preserve-3d;

  transition-timing-function: ease-out;

  background: transparent;
  color: inherit;

  font-size: $picker-ios-option-font-size;

  line-height: $picker-ios-option-height;
  backface-visibility: hidden;
  pointer-events: auto;
}

@import "./picker-column";
@import "../picker-legacy/picker.md.vars";

// Material Design Picker Column
// --------------------------------------------------

.picker-col {
  @include padding($picker-md-column-padding-top, $picker-md-column-padding-end, $picker-md-column-padding-bottom, $picker-md-column-padding-start);

  transform-style: preserve-3d;
}

.picker-prefix,
.picker-suffix,
.picker-opts {
  top: $picker-md-option-offset-y;

  transform-style: preserve-3d;

  color: inherit;

  font-size: $picker-md-option-font-size;

  line-height: $picker-md-option-height;
  pointer-events: none;
}


.picker-opt {
  @include margin(0);
  @include padding($picker-md-option-padding-top, $picker-md-option-padding-end, $picker-md-option-padding-bottom, $picker-md-option-padding-start);

  height: 43px;

  transition-timing-function: ease-out;

  background: transparent;
  color: inherit;

  font-size: $picker-md-option-font-size;

  line-height: $picker-md-option-height;
  backface-visibility: hidden;
  pointer-events: auto;
}

.picker-prefix,
.picker-suffix,
.picker-opt.picker-opt-selected {
  color: $picker-md-option-selected-color;
}

//
// Callouts
//

.bd-callout {
  --#{$prefix}link-color-rgb: var(--bd-callout-link);
  --#{$prefix}code-color: var(--bd-callout-code-color);

  padding: 1.25rem;
  margin-top: 1.25rem;
  margin-bottom: 1.25rem;
  color: var(--bd-callout-color, inherit);
  background-color: var(--bd-callout-bg, var(--bs-gray-100));
  border-left: .25rem solid var(--bd-callout-border, var(--bs-gray-300));

  h4 {
    margin-bottom: .25rem;
  }

  > :last-child {
    margin-bottom: 0;
  }

  + .bd-callout {
    margin-top: -.25rem;
  }

  .highlight {
    background-color: rgba($black, .05);
  }
}

// Variations
@each $variant in $bd-callout-variants {
  .bd-callout-#{$variant} {
    --bd-callout-color: var(--bs-#{$variant}-text-emphasis);
    --bd-callout-bg: var(--bs-#{$variant}-bg-subtle);
    --bd-callout-border: var(--bs-#{$variant}-border-subtle);
  }
}

@use "../general/table" as *;
@use "../helpers/at-media" as *;

@mixin usa-table-styles {
  table {
    @include usa-table;
  }
  .usa-table--borderless {
    @include usa-table--borderless;
  }
  .usa-table--compact {
    @include usa-table--compact;
  }
  .usa-table--striped {
    @include usa-table--striped;
  }
  .usa-table--stacked {
    @include at-media-max("mobile-lg") {
      @include table-stacked-styles;
    }
  }
  .usa-table--stacked-header {
    @include at-media-max("mobile-lg") {
      @include table-stacked-styles;
      @include table-stacked-header-styles;
    }
  }
  .width-mobile {
    .usa-table--stacked {
      @include usa-table--stacked;
    }
    .usa-table--stacked-header {
      @include usa-table--stacked-header;
    }
  }
  .usa-table-container--scrollable {
    @include usa-table-container--scrollable;
  }
}

@use "@carbon/styles/scss/reset";
@use "@carbon/styles/scss/theme";
@use "@carbon/styles/scss/themes";
@use "@carbon/styles/scss/type";
@use "@carbon/styles/scss/spacing" as *;

:root {
  @include theme.theme(themes.$white);
  background-color: var(--cds-background);
  color: var(--cds-text-primary);
}

// Utilities
.flex {
  display: flex;
}

.justify-center {
  justify-content: center;
}

.mt-10 {
  padding-block-start: $spacing-10;
}

.p-3 {
  padding: $spacing-05;
}

.playground-trigger {
  display: flex;
  align-items: center;
  justify-content: center;
  border: 1px solid theme.$border-subtle;
  block-size: $spacing-07;
  inline-size: $spacing-07;
}

.playground-trigger svg {
  fill: theme.$background-inverse;
}

.popover-title {
  @include type.type-style("heading-compact-01");

  margin-block-end: $spacing-01;
}

.popover-details {
  @include type.type-style("body-compact-01");
}
